export type ToolSafety =
  | "read"
  | "write"
  | "idempotent"
  | "approval"
  | "destructive";

export const safetyLabels: Record<ToolSafety, string> = {
  read: "ler",
  write: "escrever",
  idempotent: "escrita idempotente",
  approval: "aprovação-escrita",
  destructive: "destrutivo",
};

export interface Tool {
  /** Nome técnico, ex: "analytics_funnel" */
  name: string;
  /** Título legível */
  title: string;
  /** Slug do domínio */
  domain: string;
  /** Arquivo de origem, ex: "crm/analytics.ts" */
  file: string;
  /** Nível de risco */
  safety: ToolSafety;
  /** Descrição (verbatim) */
  description: string;
  /** Schema de entrada; ausente quando "(sem input)" */
  input?: string;
}

export interface ToolDomain {
  slug: string;
  label: string;
  count: number;
  summary?: string;
}

