/** Tools de um domínio. */
export function toolsByDomain(slug: string): Tool[] {
  return tools.filter((t) => t.domain === slug);
}

/** Metadados de um domínio pelo slug. */
export function getDomain(slug: string): ToolDomain | undefined {
  return toolDomains.find((d) => d.slug === slug);
}
